using System; using System.Linq; using Microsoft.EntityFrameworkCore; using Microsoft.Extensions.DependencyInjection; using VikashERP.Infrastructure.Data; class Program { static void Main() { var options = new DbContextOptionsBuilder<ApplicationDbContext>().UseNpgsql("Host=localhost;Port=5432;Database=Test123;Username=postgres;Password=admin123").Options; using var db = new ApplicationDbContext(options); try { var list = db.Customers.Take(1).ToList(); Console.WriteLine("Query successful, Customers count: " + list.Count); } catch(Exception ex) { Console.WriteLine("ERROR: " + ex.ToString()); } } }
